import{_ as t}from"./chunks/document-scanner-svgrepo-com.Bf6geprz.js";import{_ as d,o as e,c as o,a6 as n}from"./chunks/framework.BApAwojc.js";const P=JSON.parse('{"title":"Upload Dokumen","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"ppdgs/upload-dokumen.md","filePath":"ppdgs/upload-dokumen.md","lastUpdated":1783396232000}'),i={name:"ppdgs/upload-dokumen.md"};function r(l,a,u,s,m,p){return e(),o("div",null,[...a[0]||(a[0]=[n('<h1 id="upload-dokumen" tabindex="-1">Upload Dokumen <a class="header-anchor" href="#upload-dokumen" aria-label="Permalink to &quot;Upload Dokumen&quot;">​</a></h1><p>Sistem PPDGS tidak memiliki halaman &quot;Upload Dokumen&quot; terpisah. Setiap dokumen persyaratan diupload langsung melalui tab yang sesuai di dalam <strong>Form Biodata</strong>.</p><h2 id="lokasi-upload-dokumen" tabindex="-1">Lokasi Upload Dokumen <a class="header-anchor" href="#lokasi-upload-dokumen" aria-label="Permalink to &quot;Lokasi Upload Dokumen&quot;">​</a></h2><p>Berikut adalah tabel referensi yang menunjukkan di mana setiap dokumen harus diupload:</p><table tabindex="0"><thead><tr><th>Dokumen</th><th>Upload di Tab</th><th>Keterangan</th></tr></thead><tbody><tr><td>Foto Terbaru</td><td>Data Diri</td><td>JPG, max 1MB, 2500x1600px</td></tr><tr><td>Ijazah S1 + Profesi</td><td>Pendidikan Kedokteran</td><td>JPG, max 1MB per file</td></tr><tr><td>Sertifikat Non Formal</td><td>Pendidikan Non Formal</td><td>JPG, max 1MB</td></tr><tr><td>Cover Karya Tulis</td><td>Karya Tulis</td><td>JPG, max 1MB</td></tr><tr><td>Halaman Pertama Karya Tulis</td><td>Karya Tulis</td><td>JPG, max 1MB</td></tr><tr><td>Sertifikat Prestasi</td><td>Prestasi</td><td>JPG, max 1MB</td></tr><tr><td>Bukti Pembayaran</td><td>Menu Pembayaran (terpisah)</td><td>JPG/PNG</td></tr></tbody></table><h2 id="format-file" tabindex="-1">Format File <a class="header-anchor" href="#format-file" aria-label="Permalink to &quot;Format File&quot;">​</a></h2><p>Semua dokumen yang diupload <strong>wajib dalam format JPG</strong> dengan ketentuan:</p><ul><li>Ukuran maksimal: <strong>1 MB per file</strong></li><li>Resolusi maksimal: <strong>2500 x 1600 piksel</strong></li></ul><p>Pengecualian: Bukti pembayaran dapat diupload dalam format <strong>JPG atau PNG</strong>.</p><div class="info-card warning"><div class="info-card-title"><img src="'+t+'" alt=""> Perhatian</div><div class="info-card-content"> Pastikan dokumen terbaca dengan jelas. Dokumen yang buram atau tidak sesuai ketentuan akan ditolak oleh admin. </div></div><h2 id="status-upload" tabindex="-1">Status Upload <a class="header-anchor" href="#status-upload" aria-label="Permalink to &quot;Status Upload&quot;">​</a></h2><p>Setiap dokumen akan memiliki status:</p><table tabindex="0"><thead><tr><th>Status</th><th>Keterangan</th></tr></thead><tbody><tr><td>Belum Upload</td><td>Dokumen belum diupload</td></tr><tr><td>Terupload</td><td>Dokumen sudah diupload</td></tr><tr><td>Diverifikasi</td><td>Dokumen sedang diperiksa admin</td></tr><tr><td>Diterima</td><td>Dokumen sesuai ketentuan</td></tr><tr><td>Ditolak</td><td>Dokumen tidak sesuai, perlu upload ulang</td></tr></tbody></table><h2 id="panduan-detail" tabindex="-1">Panduan Detail <a class="header-anchor" href="#panduan-detail" aria-label="Permalink to &quot;Panduan Detail&quot;">​</a></h2><p>Untuk panduan lengkap mengenai tata cara mengisi form biodata dan mengupload dokumen, silakan buka halaman <a href="/ppdgs/form-biodata">Form Biodata</a>.</p>',15)])])}const b=d(i,[["render",r]]);export{P as __pageData,b as default};
